/**
 * FORMATEADOR UNIFICADO V4 - Específico para el mapa de Diagnosta
 * Soporta: Gemini Flash, Gemini Pro, Groq, ProtocoloAuxilio y RespuestaSano.
 */

const input = $json;
const trigger = $("Execute Workflow Trigger").item.json;
// const forense = $("ProcesadorForenseUniversal").item.json;
const forense = $('DrJunior').item.json;

let finalRecipe = null;
let provider = "SRE_SYSTEM";

// --- 1. DETECCIÓN DE FUENTE ---

// CASO A: Cualquier fallback local
if (input._meta?.fuente || input.ai_provider === "FALLBACK_SRE_LOCAL" || input.ai_provider === "SISTEMA_LOCAL_SANO") {
    finalRecipe = input.ai_recipe || input;
    provider = input.ai_provider || "LOCAL_SRE_FALLBACK";
}

// CASO B: Gemini Nativo de n8n (Message a model / Message a model1)
// Estructura: content.parts[0].text
else if (input.content?.parts?.[0]?.text) {
    const raw = input.content.parts[0].text;
    try {
        finalRecipe = JSON.parse(raw);
    } catch(e) {
        // Limpiamos los backticks de markdown (```json ... ```)
        const clean = raw.replace(/```json|```/g, '').trim();
        finalRecipe = JSON.parse(clean);
    }
    // Diferenciamos si vino del nodo 1 (Flash) o del nodo 2 (Pro) si es posible,
    // o lo marcamos como Gemini General.
    provider = "Gemini_AI_n8n";
}

// CASO C: Groq (HTTP Request)
// Estructura: choices[0].message.content
else if (input.choices?.[0]?.message?.content) {
    const raw = input.choices[0].message.content;
    try {
        finalRecipe = JSON.parse(raw);
    } catch(e) {
        const clean = raw.replace(/```json|```/g, '').trim();
        finalRecipe = JSON.parse(clean);
    }
    provider = "Groq_Llama3";
}

// CASO D: Respuesta Sano (Nodo estático)
// Identificado porque ya tiene la estructura ai_recipe
else if (input.ai_recipe) {
    finalRecipe = input.ai_recipe;
    provider = input.ai_provider || "SRE_LOCAL_STATIC";
}

// CASO E: ERROR CRÍTICO / DESCONOCIDO
else {
    finalRecipe = {
        resumen_clinico: {
            gravedad: "ROJO",
            titulo_diagnostico: "Error de Mapeo Forense",
            descripcion_humana: "El sistema recibió una respuesta pero no pudo extraer el diagnóstico de la estructura recibida.",
            requiere_humano: true
        }
    };
    provider = "MAPPING_ERROR";
}

// --- 2. ENSAMBLAJE FINAL ---
// Devolvemos el objeto exacto que el Frontend y el resto del sistema esperan
return {
    id: trigger.id,
    trace_id: trigger.trace_id,
    ai_recipe: finalRecipe,
    epidemiology_report: forense.epidemiology_report,
    ai_provider: provider,
    _internal: {
        timestamp: new Date().toISOString(),
        execution_id: $executionId,
        raw_status: trigger.vital_signs?.status_code
    }
};

const crypto = require('crypto');

// 🛡️ Extraemos las llaves directamente del entorno del contenedor Docker
const secret = $env["DIAGNOSTA_WEBHOOK_SECRET"]; 
const salt = $env["DIAGNOSTA_SALT"];
const timestamp = Date.now().toString();

// Verificación de seguridad en el "Cerebro"
if (!secret || !salt) {
  throw new Error("SRE CRITICAL: No se encontraron las llaves en el entorno de n8n. Revisa el Docker-Compose.");
}

// 🔐 Generamos la firma HMAC SHA-256
// Esta firma solo es válida por 60 segundos en el frontend
const signature = crypto
  .createHmac('sha256', secret + salt)
  .update(timestamp)
  .digest('hex');

return { 
  signature, 
  timestamp 
};

await new Promise(resolve => setImmediate(resolve));

const history = $items("Postgres (Historial)");
const trigger = $node["Execute Workflow Trigger"].json;

//const endpoint_name = trigger.name || "Endpoint Desconocido";
const endpoint_name = trigger.name || "API_Bajo_Analisis";
const status = trigger.vital_signs.status_code;
const latency_ms = trigger.vital_signs.latency_ms;
const response_evidence = trigger.vital_signs.response_preview || null;
const panic_mode = trigger.panic_mode === true;
const source = trigger.source || "AUTO_SENSOR";

// ── CLASIFICACIÓN ────────────────────────────────────────────────
let health_category = "UCI";
if (latency_ms < 300) health_category = "ATLETA";
else if (latency_ms < 600) health_category = "NORMAL";
else if (latency_ms < 1200) health_category = "FATIGADO";

const gravedad = (status >= 500 || panic_mode) ? "ROJO"
    : health_category === "UCI" ? "ROJO"
    : health_category === "FATIGADO" ? "AMARILLO"
    : "VERDE";

const requiere_humano = status >= 500 || latency_ms > 1200 || panic_mode;

// ── HISTORIAL BÁSICO ─────────────────────────────────────────────
const totalChecks = history.length;
const allLatencies = history.map(h => h.json.latency_ms).filter(l => l > 0);
const allSuccess = history.filter(h => h.json.is_success === true).length;

const avg_num = allLatencies.length
    ? Math.round(allLatencies.reduce((a,b) => a+b, 0) / allLatencies.length)
    : latency_ms;
const avgLatency = totalChecks <= 1 ? "N/A" : `${avg_num}ms`;
const uptimePercent = totalChecks <= 1
    ? "100% (Calibración Inicial)"
    : `${((allSuccess / totalChecks) * 100).toFixed(2)}%`;

// ── TENDENCIA BÁSICA (últimos 5 vs promedio) ─────────────────────
const lastFive = allLatencies.slice(0, 5);
const recentAvg = lastFive.length
    ? lastFive.reduce((a,b) => a+b, 0) / lastFive.length
    : latency_ms;
const trend = recentAvg > avg_num * 1.3 ? "DEGRADANDO"
    : recentAvg < avg_num * 0.7 ? "MEJORANDO"
    : "ESTABLE";

// ── FALLOS RECIENTES ─────────────────────────────────────────────
const fallosRecientes = history.slice(0, 5)
    .filter(h => !h.json.is_success).length;
const contexto_historico = fallosRecientes > 0
    ? `PATRÓN CRÓNICO: ${fallosRecientes}/5 checks recientes fallaron.`
    : status >= 500
    ? `FALLO AGUDO: historial limpio, este error es puntual.`
    : `Historial limpio — rendimiento consistente.`;

// ── EVIDENCIA ────────────────────────────────────────────────────
const evidence_type = response_evidence
    ? "PAYLOAD_REAL — respuesta JSON verificada"
    : "SOLO_CONECTIVIDAD — respuesta HTML/Redirección";

// ── ALERTAS ──────────────────────────────────────────────────────
const status_alert = status >= 500
    ? `\nALERTA CRÍTICA — STATUS ${status}: Fallo estructural. GRAVEDAD = ROJO independientemente de latencia.`
    : status >= 400
    ? `\nADVERTENCIA — STATUS ${status}: Petición rechazada. Investigar autenticación o parámetros.`
    : panic_mode
    ? `\nMODO PÁNICO ACTIVADO: Tratar como ROJO independientemente de métricas.`
    : "";

// ── CONTEXTO USER_TRIGGERED ──────────────────────────────────────
const context_note = source === "USER_TRIGGERED"
    ? `\nCONTEXTO: El usuario está viendo ${latency_ms}ms en su dashboard. Compara con promedio histórico (${avgLatency}) y explica si es normal o preocupante para ${endpoint_name}.`
    : "";

// ── PROMPT BASE (el Dr. Junior lo enriquecerá) ───────────────────
const prompt_base = `FICHA CLÍNICA — ${endpoint_name}

SIGNOS VITALES ACTUALES:
- Latencia: ${latency_ms}ms (${health_category})
- Status HTTP: ${status}
- Evidencia: ${evidence_type}
- Gravedad calculada: ${gravedad}
- Uptime: ${uptimePercent}
- Tendencia básica: ${trend}
- Fallos recientes: ${fallosRecientes}/5
- Contexto: ${contexto_historico}
${status_alert}
${context_note}`;

const system_instruction = `Eres el Dr. Grilo — Hybrid Forensic Surgeon SRE. Diagnosticas APIs para CEO y Senior Developers.

METODOLOGÍA:
- Cero real HTTPS: ~300ms. ATLETA <300ms · NORMAL <600ms · FATIGADO <1200ms · UCI >1200ms.
- STATUS HTTP manda: un 500 con 50ms ES crítico. La latencia baja no lo mitiga.
- Usa ${endpoint_name} por su nombre real, nunca "endpoint" o "API".
- NARRATIVA DUAL: metáfora médica breve + causa técnica cruda.
- Sin saludos. Directo: "${endpoint_name} responde en Xms, Y% sobre su promedio de Zms."

SALIDA JSON ESTRICTO — sin markdown:
{
  "resumen_clinico": { "gravedad": "${gravedad}", "titulo_diagnostico": "...", "descripcion_humana": "...", "requiere_humano": ${requiere_humano} },
  "analisis_tecnico": { "causa_raiz_probable": "...", "causa_diferencial": "...", "destinatario": "...", "patron_historico": "AGUDO|CRONICO|INTERMITENTE", "tendencia": "${trend}" },
  "protocolo_intervencion": [{ "paso": 1, "tipo": "...", "accion": "...", "comando": "..." }],
  "pronostico": { "tiempo_recuperacion": "...", "impacto_negocio": "..." },
  "firma": "Dr. Grilo - ${new Date().toISOString()}"
}`;

return {
    id: trigger.id,
    trace_id: trigger.trace_id,
    system_instruction: system_instruction,
    prompt_base: prompt_base,
    epidemiology_report: {
        uptime_score: uptimePercent,
        avg_latency: avgLatency,
        avg_num: avg_num,
        health_category: health_category,
        gravedad: gravedad,
