const comparacion_2h = avg_2h > avg_num * 1.2
    ? `Últimas 2h (${avg_2h}ms) están un ${Math.round(((avg_2h-avg_num)/avg_num)*100)}% por encima del promedio histórico — posible degradación reciente.`
    : avg_2h < avg_num * 0.8
    ? `Últimas 2h (${avg_2h}ms) están un ${Math.round(((avg_num-avg_2h)/avg_num)*100)}% por debajo del promedio — mejora reciente.`
    : `Últimas 2h (${avg_2h}ms) consistentes con el promedio histórico (${avg_num}ms).`;


// ── ENRIQUECER EL PROMPT ─────────────────────────────────────────
const prompt_input = procesador.prompt_base + `

ANÁLISIS ESTADÍSTICO (Dr. Junior):
- Mínimo histórico: ${min_lat}ms | Máximo: ${max_lat}ms
- Desviación estándar: ${std_dev}ms (${estabilidad_label})
