- Tendencia refinada: ${trend_desc}
- Racha sobre umbral: ${racha_actual} checks consecutivos
- Valor actual ${comparacion}
- ${comparacion_2h}
- ${patron_horario}`;

// ── ANALISIS_JUNIOR para ProtocoloAuxilio y RespuestaSano ────────
const analisis_junior = {
    endpoint_name: endpoint_name,
    min_latency: min_lat,
    max_latency: max_lat,
    avg_calculado: avg_num,
    std_dev: std_dev,
    estabilidad: estabilidad_label,
    percentil: percentil,
    percentil_label: percentil_label,
