    trend_desc: trend_desc,
    racha_sobre_umbral: racha_actual,
    pct_vs_avg: pct_vs_avg,
    comparacion: comparacion,
    comparacion_2h: comparacion_2h,
    patron_horario: patron_horario,
    avg_2h: avg_2h
};

// ── OUTPUT COMPLETO ──────────────────────────────────────────────
return {
    id: procesador.id,
    trace_id: procesador.trace_id,
    system_instruction: procesador.system_instruction,
    prompt_input: prompt_input,
